package search

import (
	"os"
	"path/filepath"
	"sort"
	"strings"
)

type Match struct {
	Path     string
	Distance int
}

func LevenshteinDistance(a, b string) int {
	a = strings.ToLower(a)
	b = strings.ToLower(b)
	if len(a) == 0 {
		return len(b)
	}
	if len(b) == 0 {
		return len(a)
	}

	matrix := make([][]int, len(a)+1)
	for i := range matrix {
		matrix[i] = make([]int, len(b)+1)
		matrix[i][0] = i
	}
	for j := 0; j <= len(b); j++ {
		matrix[0][j] = j
	}

	for i := 1; i <= len(a); i++ {
		for j := 1; j <= len(b); j++ {
			cost := 1
			if a[i-1] == b[j-1] {
				cost = 0
			}
			matrix[i][j] = min3(
				matrix[i-1][j]+1,
				matrix[i][j-1]+1,
				matrix[i-1][j-1]+cost,
			)
		}
	}
	return matrix[len(a)][len(b)]
}

func min3(a, b, c int) int {
	if a < b {
		if a < c {
			return a
		}
		return c
	}
	if b < c {
		return b
	}
	return c
}

func FindFuzzy(root, query string, maxDistance int) ([]Match, error) {
	var matches []Match
	err := filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return nil
		}
		name := info.Name()
		dist := LevenshteinDistance(name, query)
		if dist <= maxDistance {
			matches = append(matches, Match{Path: path, Distance: dist})
		}
		return nil
	})

	sort.Slice(matches, func(i, j int) bool {
		return matches[i].Distance < matches[j].Distance
	})

	return matches, err
}

package search

import (
	"os"
	"path/filepath"
	"testing"
)

func TestLevenshteinDistance(t *testing.T) {
	tests := []struct {
		a, b     string
		expected int
	}{
		{"kitten", "sitting", 3},
		{"hello", "hello", 0},
		{"abc", "abc", 0},
		{"abc", "ab", 1},
		{"", "abc", 3},
		{"Main", "main", 0}, // case insensitive
	}
	for _, tt := range tests {
		d := LevenshteinDistance(tt.a, tt.b)
		if d != tt.expected {
			t.Errorf("distance(%q, %q) = %d, want %d", tt.a, tt.b, d, tt.expected)
		}
	}
}

func TestFindFuzzy(t *testing.T) {
	dir := t.TempDir()
	os.WriteFile(filepath.Join(dir, "main.go"), []byte("package main"), 0644)
	os.WriteFile(filepath.Join(dir, "mian.go"), []byte("typo"), 0644)
	os.WriteFile(filepath.Join(dir, "test.go"), []byte("test"), 0644)
	os.MkdirAll(filepath.Join(dir, "sub"), 0755)
	os.WriteFile(filepath.Join(dir, "sub", "main.rs"), []byte("fn main"), 0644)

	matches, err := FindFuzzy(dir, "main.go", 2)
	if err != nil {
		t.Fatal(err)
	}
	if len(matches) < 2 {
		t.Fatalf("expected at least 2 matches, got %d", len(matches))
	}
	// First match should be exact
	if matches[0].Distance != 0 {
		t.Errorf("expected first match distance 0, got %d", matches[0].Distance)
	}
	// mian.go should be distance 2 (transposition)
	found := false
	for _, m := range matches {
		if filepath.Base(m.Path) == "mian.go" {
			found = true
			if m.Distance > 2 {
				t.Errorf("mian.go distance should be <= 2, got %d", m.Distance)
			}
		}
	}
	if !found {
		t.Error("expected mian.go in results")
	}
}
